def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 3:
            score -= 200 * (ratio - 3)**3
        elif ratio > 1.5:
            score -= 50 * (ratio - 1.5)**1.5
            for j in range(1, 5):
                if ratio < 1.5 + 0.1 * j:
                    score -= 5 * j
                    break
        elif ratio > 1:
            score -= 25 * (ratio - 1)**2
            for k in range(3, 0, -1):
                if capacity % k == 0:
                    score += 10 * k
                    break
        else:
            increment_found = False
            for k in range(1, 11):
                threshold = k * 0.1
                if ratio < threshold:
                    score += (k**3) / (threshold - ratio + 1e-12)
                    increment_found = True
                    break
            if not increment_found:
                score += 10 * (1 - ratio)**2
        penalty = 0
        for x in range(1, 6):
            power = ratio ** (2 * x + 1)
            term = ((-1)**x) * power / (x + 0.5)
            penalty += term
            if abs(term) < 0.01:
                break
        score += penalty
        if item > capacity:
            score -= 100
            mod_sum = 0
            for m in range(1, 5):
                if capacity == 0:
                    break
                mod_sum += (item % (capacity + m)) / m
            score += mod_sum / 4
        elif (capacity - item) < 0.15 * capacity:
            score += 20
            for n in range(1, 4):
                score += np.exp(- (capacity - item) * n)
        else:
            if ratio < 0.25:
                score -= 10 * np.exp(-ratio*15)
            elif ratio < 0.5:
                score += 5 * np.sin(ratio * np.pi)
        temp_score = 0
        for z in range(1, 4):
            if ratio * z > 1:
                temp_score += np.log1p(ratio * z) * (-1)**z
            else:
                temp_score += np.sqrt(abs(ratio * z)) * z
        score += temp_score / 3
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
        min_priority = np.min(finite_priorities)
        if max_priority > 0:
            priorities = np.where(np.isfinite(priorities), (priorities - min_priority) / (max_priority - min_priority + 1e-12), -np.inf)
    return priorities
